import ReactGA from 'react-ga';
import $ from 'jquery';
import './App.css';
import Header from './Components/Header';
import Footer from './Components/Footer';
import About from './Components/About';
import Resume from './Components/Resume';
import Contact from './Components/Contact';
import Testimonials from './Components/Testimonials';
import Portfolio from './Components/Portfolio';
import DocumentMeta from 'react-document-meta';

const meta = {
    title: 'Tanishq Sharma Maharaja Agrasen Institute of Technology',
    description: 'I am a fullstack developer, i can make website web apps, software, backend , front end,back end, server , frontend, deploy . i study at maharaja agrasen institute of technology,batch 2021, computer science branch,tanishq sharma, codechef , codeforces , hackerearth,tanishq sharma delhi, india , best developer delhi',
    canonical: 'http://tanishqhsarma.dev',
    meta: {
        charset: 'utf-8',
        name: {
            keywords: 'react,tanishq sharma miss india worldwide,tanishq sharma instagram,tanishq sharma kotdwara,tanishq sharma miss oman,tanishq sharma age,tanishq sharma miss india,tanishq sharma hot,tanishq sharma facebook,tanishq sharma biography,tanishq sharma indias next top model, tanishq sharma wikipedia,tanishq jewellers,gold sharma,au sharma,jewellery,necklace,tanishq ,maharaja ,agrasen ,of ,technology ,delhi,tanishq sharma codechef,codeforces,hackerearth,delhi,github,lru cache,url shortner,iiit ,hyderabad,software developer india , tanishq sharma website'}
    }
  }

class App extends Component {

  constructor(props){
    super(props);
    this.state = {
      foo: 'bar',
      resumeData: {}
    };

    ReactGA.initialize('UA-110570651-1');
    ReactGA.pageview(window.location.pathname);

  }

  getResumeData(){
    $.ajax({
      url:'/resumeData.json',
      dataType:'json',
      cache: false,
      success: function(data){
        this.setState({resumeData: data});
      }.bind(this),
      error: function(xhr, status, err){
        console.log(err);
        alert(err);
      }
    });
  }

  componentDidMount(){
    this.getResumeData();
  }

  render() {
    return (
      <div className="App">
       <DocumentMeta {...meta} />

        <Header data={this.state.resumeData.main}/>
        <About data={this.state.resumeData.main}/>
        <Resume data={this.state.resumeData.resume}/>
        <Portfolio data={this.state.resumeData.portfolio}/>
        <Testimonials data={this.state.resumeData.testimonials}/>
        <Contact data={this.state.resumeData.main}/>
        <Footer data={this.state.resumeData.main}/>
      </div>
    );
  }
}

export default App;



